import React, { useMemo, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getAllBlogs } from "../features/ads/adsSlice";

const BannerAd = ({ subcategory }) => {
  const dispatch = useDispatch();
  const { blog: adData } = useSelector((state) => state.blog);

  useEffect(() => {
    if (!adData || adData.length === 0) {
      dispatch(getAllBlogs());
    }
  }, [dispatch, adData]);

  const bannerAds = useMemo(() => {
    return (adData || []).filter(
      (item) =>
        item.category === "Banner" &&
        item.subcategory?.toLowerCase() === subcategory?.toLowerCase(),
    );
  }, [adData, subcategory]);

  if (bannerAds.length === 0) return null;

  // Pick the first matching banner for simplicity
  const ad = bannerAds[0];

  return (
    <div className="w-full my-12 px-4 lg:px-8">
      <div className="max-w-[1440px] mx-auto relative group overflow-hidden rounded-3xl shadow-lg hover:shadow-2xl transition-all duration-500">
        <div className="flex flex-col md:flex-row bg-white overflow-hidden">
          {/* Ad Content */}
          <div className="flex-1 p-8 md:p-12 flex flex-col justify-center">
            <span className="text-teal-600 text-xs font-black uppercase tracking-[0.4em] mb-3 block">
              Limited Time Selection
            </span>
            <h2 className="text-3xl md:text-4xl lg:text-5xl font-black text-gray-900 leading-tight mb-4">
              {ad.title}
            </h2>
            <div
              className="text-gray-600 text-lg font-medium mb-8 max-w-lg prose prose-teal"
              dangerouslySetInnerHTML={{ __html: ad.description }}
            ></div>
            <div>
              <button className="px-8 py-3.5 bg-gray-900 text-white font-black uppercase tracking-widest text-sm rounded-xl hover:bg-teal-600 transition-colors shadow-lg">
                Shop {subcategory} Now
              </button>
            </div>
          </div>

          {/* Ad Image */}
          {ad.images && ad.images[0] && (
            <div className="flex-1 relative min-h-[300px] overflow-hidden">
              <img
                src={ad.images[0].secure_url}
                alt={ad.title}
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
              />
              <div className="absolute inset-0 bg-gradient-to-r from-white via-white/20 to-transparent md:block hidden" />
            </div>
          )}
        </div>

        {/* Floating Decor */}
        <div className="absolute top-4 left-4 bg-yellow-400 text-black text-[10px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-md">
          Promoted
        </div>
      </div>
    </div>
  );
};

export default BannerAd;
